import React from 'react';
import { Heart } from 'lucide-react';
import TrackList from '../components/TrackList';

export default function Library({ playTrack, toggleLike, isLiked, currentTrack, isPlaying, likedTracks, recentTracks }) {
  return (
    <div className="mood-page">
      <div className="topbar" style={{ padding: '24px 0 0 0', position: 'static', marginBottom: 32 }}>
        <h1 style={{ fontSize: 28, fontWeight: 900 }}>Your Library</h1>
      </div>

      <section style={{ marginBottom: 48 }}>
        <div className="section-title">
          <span style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            <Heart size={20} color="#1db954" fill="#1db954" /> Liked Songs
          </span>
          <span style={{ fontSize: 14, color: 'var(--text-subdued)' }}>{likedTracks?.length || 0} songs</span>
        </div>

        {!likedTracks || likedTracks.length === 0 ? (
          <div className="empty-state" style={{ padding: '40px 0' }}>
            <div style={{ fontSize: 48, marginBottom: 12 }}>💔</div>
            <h2>No liked songs yet</h2>
            <p>Hit the heart icon on any track to save it here</p>
          </div>
        ) : (
          <TrackList
            tracks={likedTracks}
            playTrack={playTrack}
            toggleLike={toggleLike}
            isLiked={isLiked}
            currentTrack={currentTrack}
            isPlaying={isPlaying}
          />
        )}
      </section>

      <section>
        <div className="section-title">
          <span>Recently Played</span>
          <span style={{ fontSize: 14, color: 'var(--text-subdued)' }}>{recentTracks?.length || 0} tracks</span>
        </div>

        {!recentTracks || recentTracks.length === 0 ? (
          <div className="empty-state" style={{ padding: '40px 0' }}>
            <div style={{ fontSize: 48, marginBottom: 12 }}>🎧</div>
            <h2>Nothing played yet</h2>
            <p>Start listening and your history will appear here</p>
          </div>
        ) : (
          <TrackList
            tracks={recentTracks}
            playTrack={playTrack}
            toggleLike={toggleLike}
            isLiked={isLiked}
            currentTrack={currentTrack}
            isPlaying={isPlaying}
          />
        )}
      </section>
    </div>
  );
}
